SELECT o.*, GROUP_CONCAT(od.`name` SEPARATOR ',') AS orderDishes FROM orders o LEFT JOIN order_detail od ON o.id = od.order_id
and o.order_time between #{beginTime} and #{endTime}
AND o.phone LIKE CONCAT('%', #{phone}, '%')
AND o.status = #{status}
AND o.number LIKE CONCAT('%', #{number}, '%')
GROUP BY o.id, o.order_time ORDER BY o.order_time DESC

SELECT -- 订单主表（orders）所有字段（用别名避免与明细字段冲突） o.id AS order_id, o.number, o.status, o.user_id AS order_user_id, o.address_book_id AS order_address_book_id, o.order_time, o.checkout_time, o.pay_method, o.pay_status, o.amount AS order_amount, o.remark, o.user_name, o.phone, o.address, o.consignee, o.cancel_reason, o.rejection_reason, o.cancel_time, o.estimated_delivery_time, o.delivery_status, o.delivery_time, o.pack_amount, o.tableware_number, o.tableware_status,
-- 订单明细表（order_detail）所有字段（明细一条记录对应一个对象） od.id AS detail_id, od.name AS detail_name, od.dish_id AS detail_dish_id, od.setmeal_id AS detail_setmeal_id, od.dish_flavor AS detail_dish_flavor, od.number AS detail_number, od.amount AS detail_amount, od.image AS detail_image, od.order_id AS detail_order_id FROM orders o LEFT JOIN order_detail od ON o.id = od.order_id
AND o.status = #{status}
and user_id = #{userId}
ORDER BY o.order_time DESC

select sum(amount) from orders


        and status = #{status}


        and order_time >= #{begin}


        and order_time <= #{end}

select count(id) from orders


        and status = #{status}


        and order_time >= #{begin}


        and order_time <= #{end}

select od.name name,sum(od.number) number from order_detail od ,orders o where od.order_id = o.id and o.status = 5
and order_time >= #{begin}
and order_time <= #{end}
group by name order by number desc limit 0, 10
